mapper.select:
SELECT a.*
FROM eb_assess a

	AND a.deleted_at IS NULL

		AND a.entid = #{query.entid}


		AND a.user_id = #{query.userId}


		AND a.superior_id = #{query.superiorId}


		AND a.plan_id = #{query.planId}


		AND a.status = #{query.status}


ORDER BY a.id DESC

SELECT ad.id
FROM eb_admin ad
WHERE ad.deleted_at IS NULL
  AND ad.entid = #{entid}
  AND ad.id NOT IN (
      SELECT a.user_id FROM eb_assess a
      WHERE a.entid = #{entid}
        AND a.plan_id = #{planId}
        AND a.deleted_at IS NULL
  )
